function getDiscount(user) {
  // Guard clauses — ранний возврат
  if (!user) return 0;
  if (!user.isActive) return 0;

  // Плоская логика вместо вложенности
  if (user.totalPurchases > 10000) {
    return user.memberSince < 2020 ? 20 : 15;
  }
  if (user.totalPurchases > 5000) return 10;
  return 5;
}

// Lookup table вместо if/else цепочки
const STATUS_LABELS = {
  active: 'Активен',
  inactive: 'Неактивен',
  pending: 'Ожидает',
  banned: 'Заблокирован',
};

function getLabel(status) {
  return STATUS_LABELS[status] ?? 'Неизвестно';
}
